INSERT INTO app.job_applications (
  owner_userid, company_id, position, status, start_date, location, source, link,
  application_date, company_notes, createdat, updatedat
)
SELECT
  'e5fc0208-4fa8-4318-97b0-e08af776ce7a', nc.id, na.position, na.status, na.start_date, na.location,
  na.source, na.link, na.application_date, na.company_notes, na.createdat, na.updatedat
FROM new_applications na
JOIN new_companies nc ON lower(nc.name) = lower(na.company_name)
WHERE NOT EXISTS (
  SELECT 1 FROM app.job_applications WHERE owner_userid = 'e5fc0208-4fa8-4318-97b0-e08af776ce7a'
);

